import{_ as a,c as o,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Aviso de ToS: Riscos de Conta e Práticas de Segurança | Antigravity Auth","description":"Aprenda sobre os riscos de uso do plugin Antigravity Auth e práticas de segurança de conta. Entenda cenários de alto risco, mecanismo de shadow ban e diferenças de limite de taxa, domine estratégias de múltiplas contas, controle de uso e métodos de aquecimento de conta.","frontmatter":{"title":"Aviso de ToS: Riscos de Conta e Práticas de Segurança | Antigravity Auth","sidebarTitle":"Evite o Banimento de Conta","subtitle":"Aviso de ToS: Riscos de Conta e Práticas de Segurança","description":"Aprenda sobre os riscos de uso do plugin Antigravity Auth e práticas de segurança de conta. Entenda cenários de alto risco, mecanismo de shadow ban e diferenças de limite de taxa, domine estratégias de múltiplas contas, controle de uso e métodos de aquecimento de conta.","tags":["FAQ","Aviso de Risco","Segurança de Conta"],"prerequisite":["start-quick-install"],"order":5},"headers":[],"relativePath":"pt/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md","filePath":"pt/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"}'),r={name:"pt/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"};function s(n,e,d,l,c,u){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="aviso-de-tos" tabindex="-1">Aviso de ToS <a class="header-anchor" href="#aviso-de-tos" aria-label="Permalink to &quot;Aviso de ToS&quot;">​</a></h1><p>Após concluir esta lição, você entenderá os riscos potenciais ao usar o plugin Antigravity Auth e como proteger a segurança da sua conta Google.</p><h2 id="o-desafio-que-voce-enfrenta-agora" tabindex="-1">O Desafio que Você Enfrenta Agora <a class="header-anchor" href="#o-desafio-que-voce-enfrenta-agora" aria-label="Permalink to &quot;O Desafio que Você Enfrenta Agora&quot;">​</a></h2><p>Você está considerando usar o plugin Antigravity Auth para acessar os modelos de IA do Google Antigravity, mas tem algumas preocupações:</p><ul><li>Viu relatos na comunidade de contas sendo banidas ou recebendo shadow ban</li><li>Preocupado que usar ferramentas não oficiais viole os Termos de Serviço do Google</li><li>Incerto se deve usar uma conta nova ou antiga</li><li>Quer saber como reduzir os riscos</li></ul><p>Essas preocupações são razoáveis. Usar qualquer ferramenta não oficial envolve certos riscos, e este artigo ajudará você a entender os pontos de risco específicos e estratégias de resposta.</p><h2 id="quando-voce-precisa-desta-licao" tabindex="-1">Quando Você Precisa Desta Lição <a class="header-anchor" href="#quando-voce-precisa-desta-licao" aria-label="Permalink to &quot;Quando Você Precisa Desta Lição&quot;">​</a></h2><ul><li><strong>Antes de instalar o plugin</strong>: Entenda os riscos antes de decidir usar</li><li><strong>Ao escolher uma conta</strong>: Decida qual conta Google usar para autenticação</li><li><strong>Ao encontrar banimento</strong>: Entenda possíveis causas e medidas preventivas</li><li><strong>Ao registrar nova conta</strong>: Evite padrões de operação de alto risco</li></ul><hr><h2 id="visao-geral-dos-riscos-principais" tabindex="-1">Visão Geral dos Riscos Principais <a class="header-anchor" href="#visao-geral-dos-riscos-principais" aria-label="Permalink to &quot;Visão Geral dos Riscos Principais&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Aviso Importante</p><p><strong>Usar este plugin pode violar os Termos de Serviço (Terms of Service) do Google.</strong></p><p>Um pequeno número de usuários relatou que suas contas Google foram banidas ou receberam shadow ban (restrição de acesso sem notificação explícita).</p><p><strong>Usar este plugin significa que você aceita as seguintes declarações:</strong></p><ol><li>Esta é uma ferramenta não oficial, não reconhecida ou endossada pelo Google</li><li>Sua conta Google pode ser suspensa ou permanentemente banida</li><li>Você assume todos os riscos e consequências do uso deste plugin</li></ol></div><h3 id="o-que-e-shadow-ban" tabindex="-1">O que é Shadow Ban? <a class="header-anchor" href="#o-que-e-shadow-ban" aria-label="Permalink to &quot;O que é Shadow Ban?&quot;">​</a></h3><p><strong>Shadow Ban</strong> é uma medida restritiva que o Google aplica a contas suspeitas. Diferente de banimento direto, o shadow ban não exibe mensagens de erro claras, mas:</p><ul><li>Requisições de API retornam erros 403 ou 429</li><li>A cota aparece disponível, mas não pode ser usada</li><li>Outras contas funcionam normalmente, apenas a conta marcada é afetada</li></ul><p>Shadow bans geralmente duram muito tempo (dias a semanas) e não podem ser recuperados por apelação.</p><hr><h2 id="cenarios-de-alto-risco" tabindex="-1">Cenários de Alto Risco <a class="header-anchor" href="#cenarios-de-alto-risco" aria-label="Permalink to &quot;Cenários de Alto Risco&quot;">​</a></h2><p>Os seguintes cenários aumentam significativamente o risco de sua conta ser marcada ou banida:</p><h3 id="🚨-cenario-1-conta-google-totalmente-nova" tabindex="-1">🚨 Cenário 1: Conta Google Totalmente Nova <a class="header-anchor" href="#🚨-cenario-1-conta-google-totalmente-nova" aria-label="Permalink to &quot;🚨 Cenário 1: Conta Google Totalmente Nova&quot;">​</a></h3><p><strong>Nível de Risco: Extremamente Alto</strong></p><p>Contas Google recém-registradas usando este plugin têm probabilidade muito alta de banimento. Razões:</p><ul><li>Novas contas carecem de dados históricos de comportamento, facilmente marcadas pelo sistema de detecção de abuso do Google</li><li>Grande volume de chamadas de API em novas contas é visto como comportamento anormal</li><li>O Google tem auditoria mais rigorosa para novas contas</li></ul><p><strong>Recomendação</strong>: Não crie novas contas especificamente para este plugin.</p><h3 id="🚨-cenario-2-nova-conta-assinatura-pro-ultra" tabindex="-1">🚨 Cenário 2: Nova Conta + Assinatura Pro/Ultra <a class="header-anchor" href="#🚨-cenario-2-nova-conta-assinatura-pro-ultra" aria-label="Permalink to &quot;🚨 Cenário 2: Nova Conta + Assinatura Pro/Ultra&quot;">​</a></h3><p><strong>Nível de Risco: Extremamente Alto</strong></p><p>Contas recém-registradas que imediatamente assinam serviços Pro ou Ultra do Google são frequentemente marcadas e banidas. Razões:</p><ul><li>Padrão de alto uso após assinatura em novas contas parece abuso</li><li>O Google tem auditoria mais rigorosa para novos usuários pagantes</li><li>Este padrão difere muito do caminho de crescimento de usuários normais</li></ul><p><strong>Recomendação</strong>: Deixe a conta &quot;crescer naturalmente&quot; por um período (pelo menos alguns meses) antes de considerar assinatura.</p><h3 id="🟡-cenario-3-grande-volume-de-requisicoes-em-curto-periodo" tabindex="-1">🟡 Cenário 3: Grande Volume de Requisições em Curto Período <a class="header-anchor" href="#🟡-cenario-3-grande-volume-de-requisicoes-em-curto-periodo" aria-label="Permalink to &quot;🟡 Cenário 3: Grande Volume de Requisições em Curto Período&quot;">​</a></h3><p><strong>Nível de Risco: Alto</strong></p><p>Fazer grande volume de requisições de API em curto período, ou usar frequentemente proxies paralelos/múltiplas sessões, acionará limites de taxa e detecção de abuso. Razões:</p><ul><li>O padrão de requisições do OpenCode é mais denso que aplicativos nativos (chamadas de ferramentas, tentativas, streaming, etc.)</li><li>Requisições de alta concorrência acionam mecanismos de proteção do Google</li></ul><p><strong>Recomendação</strong>:</p><ul><li>Controle frequência de requisições e número de concorrência</li><li>Evite iniciar múltiplos proxies paralelos simultaneamente</li><li>Use rotação de múltiplas contas para distribuir requisições</li></ul><h3 id="🟡-cenario-4-usar-conta-google-unica" tabindex="-1">🟡 Cenário 4: Usar Conta Google Única <a class="header-anchor" href="#🟡-cenario-4-usar-conta-google-unica" aria-label="Permalink to &quot;🟡 Cenário 4: Usar Conta Google Única&quot;">​</a></h3><p><strong>Nível de Risco: Médio</strong></p><p>Se você tem apenas uma conta Google e depende dela para acessar serviços críticos (Gmail, Drive, etc.), o risco é maior. Razões:</p><ul><li>Banimento de conta afetará seu trabalho diário</li><li>Não pode ser recuperado por apelação</li><li>Falta de plano alternativo</li></ul><p><strong>Recomendação</strong>: Use uma conta independente que não dependa de serviços críticos.</p><hr><h2 id="recomendacoes-de-melhores-praticas" tabindex="-1">Recomendações de Melhores Práticas <a class="header-anchor" href="#recomendacoes-de-melhores-praticas" aria-label="Permalink to &quot;Recomendações de Melhores Práticas&quot;">​</a></h2><h3 id="✅-praticas-recomendadas" tabindex="-1">✅ Práticas Recomendadas <a class="header-anchor" href="#✅-praticas-recomendadas" aria-label="Permalink to &quot;✅ Práticas Recomendadas&quot;">​</a></h3><p><strong>1. Use Contas Google Estabelecidas</strong></p><p>Priorize contas Google que já estão em uso há algum tempo (recomendado 6 meses ou mais):</p><ul><li>Tenha histórico normal de uso de serviços Google (Gmail, Drive, Google Search, etc.)</li><li>Sem histórico de violações</li><li>Conta vinculada a número de telefone e verificada</li></ul><p><strong>2. Configure Múltiplas Contas</strong></p><p>Adicione múltiplas contas Google, distribua requisições através de rotação:</p><ul><li>Configure pelo menos 2-3 contas</li><li>Use estratégia <code>account_selection_strategy: &quot;hybrid&quot;</code> (padrão)</li><li>Troque automaticamente de conta ao encontrar limite de taxa</li></ul><p><strong>3. Controle o Volume de Uso</strong></p><ul><li>Evite requisições densas em curto período</li><li>Reduza o número de proxies paralelos</li><li>Configure <code>max_rate_limit_wait_seconds: 0</code> em <code>antigravity.json</code> para falhar rapidamente em vez de tentar novamente</li></ul><p><strong>4. Monitore Status da Conta</strong></p><p>Verifique regularmente o status da conta:</p><ul><li>Veja <code>rateLimitResetTimes</code> em <code>~/.config/opencode/antigravity-accounts.json</code></li><li>Habilite logs de debug: <code>OPENCODE_ANTIGRAVITY_DEBUG=1 opencode</code></li><li>Ao encontrar erros 403/429, pause o uso por 24-48 horas</li></ul><p><strong>5. &quot;Aqueça&quot; Primeiro na Interface Oficial</strong></p><p>Método eficaz relatado por usuários da comunidade:</p><ol><li>Faça login no navegador em <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a></li><li>Execute alguns prompts simples (como &quot;olá&quot;, &quot;quanto é 2+2&quot;)</li><li>Após 5-10 chamadas bem-sucedidas, use o plugin</li></ol><p><strong>Princípio</strong>: Usar a conta através da interface oficial faz o Google reconhecer como comportamento normal de usuário, reduzindo o risco de ser marcado.</p><h3 id="❌-praticas-a-evitar" tabindex="-1">❌ Práticas a Evitar <a class="header-anchor" href="#❌-praticas-a-evitar" aria-label="Permalink to &quot;❌ Práticas a Evitar&quot;">​</a></h3><ul><li>❌ Criar novas contas Google especificamente para este plugin</li><li>❌ Assinar Pro/Ultra imediatamente em contas recém-registradas</li><li>❌ Usar conta única de serviços críticos (como email de trabalho)</li><li>❌ Tentar repetidamente após acionar limite 429</li><li>❌ Iniciar grande número de proxies paralelos simultaneamente</li><li>❌ Submeter <code>antigravity-accounts.json</code> para controle de versão</li></ul><hr><h2 id="perguntas-frequentes" tabindex="-1">Perguntas Frequentes <a class="header-anchor" href="#perguntas-frequentes" aria-label="Permalink to &quot;Perguntas Frequentes&quot;">​</a></h2><h3 id="q-minha-conta-foi-banida-posso-apelar" tabindex="-1">Q: Minha conta foi banida, posso apelar? <a class="header-anchor" href="#q-minha-conta-foi-banida-posso-apelar" aria-label="Permalink to &quot;Q: Minha conta foi banida, posso apelar?&quot;">​</a></h3><p><strong>A: Não.</strong></p><p>Se o banimento ou shadow ban foi acionado pela detecção de abuso do Google através deste plugin, geralmente não pode ser recuperado por apelação. Razões:</p><ul><li>Banimento é acionado automaticamente com base no padrão de uso de API</li><li>O Google tem atitude rigorosa sobre uso de ferramentas não oficiais</li><li>Ao apelar, você precisa explicar o uso da ferramenta, mas o próprio plugin pode ser visto como violação</li></ul><p><strong>Recomendação</strong>:</p><ul><li>Use outras contas não afetadas</li><li>Se todas as contas foram banidas, use diretamente <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a></li><li>Evite continuar tentando em contas banidas</li></ul><h3 id="q-usar-este-plugin-definitivamente-resultara-em-banimento" tabindex="-1">Q: Usar este plugin definitivamente resultará em banimento? <a class="header-anchor" href="#q-usar-este-plugin-definitivamente-resultara-em-banimento" aria-label="Permalink to &quot;Q: Usar este plugin definitivamente resultará em banimento?&quot;">​</a></h3><p><strong>A: Não necessariamente.</strong></p><p>A maioria dos usuários não encontrou problemas ao usar este plugin. O risco depende de:</p><ul><li>Idade da conta e comportamento histórico</li><li>Frequência de uso e padrão de requisições</li><li>Se segue as melhores práticas</li></ul><p><strong>Avaliação de Risco</strong>:</p><ul><li>Conta antiga + uso moderado + rotação de múltiplas contas → Baixo risco</li><li>Conta nova + requisições densas + conta única → Alto risco</li></ul><h3 id="q-qual-e-a-diferenca-entre-shadow-ban-e-limite-de-taxa" tabindex="-1">Q: Qual é a diferença entre shadow ban e limite de taxa? <a class="header-anchor" href="#q-qual-e-a-diferenca-entre-shadow-ban-e-limite-de-taxa" aria-label="Permalink to &quot;Q: Qual é a diferença entre shadow ban e limite de taxa?&quot;">​</a></h3><p><strong>A: Natureza diferente, métodos de recuperação também diferentes.</strong></p><table tabindex="0"><thead><tr><th>Característica</th><th>Shadow Ban</th><th>Limite de Taxa (429)</th></tr></thead><tbody><tr><td>Causa do Acionamento</td><td>Detecção de abuso, marcado como suspeito</td><td>Frequência de requisições excede cota</td></tr><tr><td>Código de Erro</td><td>403 ou falha silenciosa</td><td>429 Too Many Requests</td></tr><tr><td>Duração</td><td>Dias a semanas</td><td>Horas a um dia</td></tr><tr><td>Método de Recuperação</td><td>Não pode recuperar, precisa usar outra conta</td><td>Aguardar reset ou trocar conta</td></tr><tr><td>Pode Prevenir</td><td>Seguir melhores práticas reduz risco</td><td>Controlar frequência de requisições</td></tr></tbody></table><h3 id="q-posso-usar-conta-google-corporativa" tabindex="-1">Q: Posso usar conta Google corporativa? <a class="header-anchor" href="#q-posso-usar-conta-google-corporativa" aria-label="Permalink to &quot;Q: Posso usar conta Google corporativa?&quot;">​</a></h3><p><strong>A: Não recomendado.</strong></p><p>Contas corporativas geralmente estão vinculadas a serviços e dados críticos, banimento tem impacto mais sério. Além disso:</p><ul><li>Contas corporativas têm auditoria mais rigorosa</li><li>Pode violar políticas de TI da empresa</li><li>Risco é assumido individualmente, mas afeta a equipe</li></ul><p><strong>Recomendação</strong>: Use conta pessoal.</p><h3 id="q-multiplas-contas-podem-evitar-completamente-o-banimento" tabindex="-1">Q: Múltiplas contas podem evitar completamente o banimento? <a class="header-anchor" href="#q-multiplas-contas-podem-evitar-completamente-o-banimento" aria-label="Permalink to &quot;Q: Múltiplas contas podem evitar completamente o banimento?&quot;">​</a></h3><p><strong>A: Não pode evitar completamente, mas pode reduzir o impacto.</strong></p><p>Função de múltiplas contas:</p><ul><li>Distribuir requisições, reduzir probabilidade de conta única acionar limites</li><li>Se uma conta for banida, outras contas ainda estão disponíveis</li><li>Trocar automaticamente ao encontrar limites, melhorar disponibilidade</li></ul><p><strong>Mas múltiplas contas não são &quot;amuleto de proteção&quot;</strong>:</p><ul><li>Se todas as contas acionarem detecção de abuso, podem todas ser banidas</li><li>Não abuse de múltiplas contas para requisições densas</li><li>Cada conta ainda precisa seguir melhores práticas</li></ul><hr><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>Após ler esta lição, você deve saber:</p><ul><li>[ ] Usar este plugin pode violar Google ToS, risco por sua conta</li><li>[ ] Nova conta + assinatura Pro/Ultra é cenário de alto risco</li><li>[ ] Recomendado usar contas Google estabelecidas</li><li>[ ] Configurar múltiplas contas pode distribuir riscos</li><li>[ ] Contas banidas não podem ser recuperadas por apelação</li><li>[ ] Controlar frequência de requisições e volume de uso é importante</li></ul><hr><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><p>Esta lição apresentou os riscos potenciais ao usar o plugin Antigravity Auth:</p><ol><li><strong>Riscos Principais</strong>: Pode violar Google ToS, conta pode ser banida ou receber shadow ban</li><li><strong>Cenários de Alto Risco</strong>: Novas contas, nova conta + assinatura, requisições densas, conta crítica única</li><li><strong>Melhores Práticas</strong>: Use contas antigas, configure múltiplas contas, controle volume de uso, monitore status, &quot;aqueça&quot; primeiro</li><li><strong>Perguntas Frequentes</strong>: Não pode apelar, risco varia por pessoa, múltiplas contas podem reduzir impacto</li></ol><p>Antes de usar este plugin, avalie cuidadosamente os riscos. Se você não pode aceitar as consequências de possível banimento de conta, recomenda-se usar diretamente <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a>.</p><hr><h2 id="apendice-referencia-de-codigo-fonte" tabindex="-1">Apêndice: Referência de Código Fonte <a class="header-anchor" href="#apendice-referencia-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência de Código Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver localização do código fonte</strong></summary><blockquote><p>Última atualização: 2026-01-23</p></blockquote><p>Este conteúdo da lição é baseado na seção de aviso de risco da documentação README do projeto (README.md:23-40), não envolve implementação de código específico.</p><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linhas</th></tr></thead><tbody><tr><td>Declaração de Aviso de ToS</td><td><a href="https://github.com/NoeFabris/opencode-antigravity-auth/blob/main/README.md#L23-L40" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>23-40</td></tr></tbody></table></details>',99)])])}const g=a(r,[["render",s]]);export{m as __pageData,g as default};
